// Group array by key
const groupBy = (arr, key) =>
  arr.reduce((acc, item) => {
    (acc[item[key]] ??= []).push(item)
    return acc
  }, {})

// Debounce
const debounce = (fn, delay) => {
  let timer
  return (...args) => {
    clearTimeout(timer)
    timer = setTimeout(() => fn(...args), delay)
  }
}

// Sleep
const sleep = (ms) => new Promise(r => setTimeout(r, ms))

// Pick keys from object
const pick = (obj, keys) =>
  Object.fromEntries(keys.map(k => [k, obj[k]]))

// Read a file
func readFile(path string) (string, error) {
	data, err := os.ReadFile(path)
	if err != nil {
		return "", fmt.Errorf("readFile: %w", err)
	}
	return string(data), nil
}

// Fan-out with goroutines
func fanOut(items []string, worker func(string) error) error {
	var wg sync.WaitGroup
	errCh := make(chan error, len(items))
	for _, item := range items {
		wg.Add(1)
		go func(s string) {
			defer wg.Done()
			if err := worker(s); err != nil {
				errCh <- err
			}
		}(item)
	}
	wg.Wait()
	close(errCh)
	return <-errCh
}

// Read lines from a file
use std::{fs, io::{self, BufRead}};

fn read_lines(path: &str) -> io::Result<Vec<String>> {
    let file = fs::File::open(path)?;
    io::BufReader::new(file).lines().collect()
}

// Retry with backoff
fn retry<T, E, F>(mut f: F, attempts: u32) -> Result<T, E>
where
    F: FnMut() -> Result<T, E>,
{
    for i in 0..attempts {
        match f() {
            ok @ Ok(_) => return ok,
            Err(_) if i + 1 < attempts => {
                std::thread::sleep(
                    std::time::Duration::from_millis(100 * 2u64.pow(i))
                );
            }
            err => return err,
        }
    }
    unreachable!()
}
